from flask import Flask, request, jsonify
from werkzeug.security import check_password_hash, generate_password_hash
from logging.handlers import RotatingFileHandler
import logging

app = Flask(__name__)

# Dummy list to represent users in a database
users = [
    {
        'username': 'user1',
        'email': 'user1@example.com',
        'password': generate_password_hash('password', method='sha256')
    }
]

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()

    username = data.get('username')
    password = data.get('password')
    email = data.get('email')
    ip_address = request.remote_addr
    user_agent = request.user_agent
    authentication_result = 'Failed'

    user = next((user for user in users if user["username"] == username), None)
    
    if user and check_password_hash(user['password'], password):
        authentication_result = 'Successful'

    log.info(f'Login attempt: Username - {username}, Email - {email}, '
             f'Authentication Result - {authentication_result}, '
             f'IP Address - {ip_address}, User Agent - {user_agent}')    

    if user and authentication_result == 'Successful':
        return jsonify({'message': 'Login Successful.'})
    else:
        return jsonify({'message': 'Login Failed.'})

if __name__ == "__main__":
    handler = RotatingFileHandler('application.log', maxBytes=10000, backupCount=3)
    log = logging.getLogger(__name__)
    log.setLevel(logging.INFO)
    log.addHandler(handler)
    
    app.run(debug=False)